const https = require('https');

const store = '7089d1-4e.myshopify.com';
const token = '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';

const query = JSON.stringify({
  query: \`{
    orders(first: 50, query: \"created_at:>=2026-04-01\") {
      edges {
        node {
          id
          name
          createdAt
          totalPriceSet { shopMoney { amount } }
          lineItems(first: 10) {
            edges {
              node {
                title
                quantity
                variant { price }
              }
            }
          }
        }
      }
    }
  }\`
});

const options = {
  hostname: store,
  path: '/admin/api/2023-10/graphql.json',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Shopify-Access-Token': token,
    'Content-Length': Buffer.byteLength(query)
  }
};

const req = https.request(options, (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    const json = JSON.parse(data);
    const orders = json.data?.orders?.edges || [];
    console.log('Total orders in April:', orders.length);
    let totalSales = 0;
    let itemCounts = {};
    orders.forEach(o => {
      const price = parseFloat(o.node.totalPriceSet.shopMoney.amount);
      totalSales += price;
      o.node.lineItems.edges.forEach(li => {
        const title = li.node.title;
        const qty = li.node.quantity;
        if (!itemCounts[title]) itemCounts[title] = { qty: 0, orders: 0 };
        itemCounts[title].qty += qty;
        itemCounts[title].orders++;
      });
    });
    console.log('Total sales (Apr):', Math.round(totalSales));
    console.log('Items:', JSON.stringify(itemCounts, null, 2));
  });
});
req.on('error', e => console.error('Error:', e.message));
req.write(query);
req.end();
