node -e "
const https = require('https');

const store = '7089d1-4e.myshopify.com';
const token = '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';

// Get order-by-order breakdown for April
const query = JSON.stringify({
  query: \`{
    orders(first: 50, query: \"created_at:>=2026-04-01\", sortKey: CREATED_AT) {
      edges {
        node {
          name
          createdAt
          totalPriceSet { shopMoney { amount } }
          lineItems(first: 15) {
            edges {
              node {
                title
                quantity
              }
            }
          }
        }
      }
    }
  }\`
});

const options = {
  hostname: store,
  path: '/admin/api/2023-10/graphql.json',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Shopify-Access-Token': token,
    'Content-Length': Buffer.byteLength(query)
  }
};

const req = https.request(options, (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    const json = JSON.parse(data);
    const orders = json.data?.orders?.edges || [];

    // Daily breakdown
    let dailyStats = {};
    let totalBowls = 0;
    let totalSales = 0;

    orders.forEach(o => {
      const date = o.node.createdAt.substring(0, 10);
      const price = parseFloat(o.node.totalPriceSet.shopMoney.amount);
      if (!dailyStats[date]) dailyStats[date] = { orders: 0, sales: 0, bowls: 0 };
      dailyStats[date].orders++;
      dailyStats[date].sales += price;
      totalSales += price;

      // Count bowls (excluding packaging)
      o.node.lineItems.edges.forEach(li => {
        const title = li.node.title;
        const qty = li.node.quantity;
        if (!title.includes('桐箱') && !title.includes('紙袋')) {
          dailyStats[date].bowls += qty;
          totalBowls += qty;
        }
      });
    });

    console.log('=== 4月日次サマリー ===');
    Object.entries(dailyStats).sort().forEach(([date, stats]) => {
      console.log(date + ': ' + stats.orders + '件 / ¥' + Math.round(stats.sales) + ' / ' + stats.bowls + '碗');
    });
    console.log('---');
    console.log('合計: ' + orders.length + '件 / ¥' + Math.round(totalSales) + ' / ' + totalBowls + '碗');
    console.log('AOV: ¥' + Math.round(totalSales / orders.length));

    // 4月経過日数と着地見込
    const daysElapsed = 3; // 4/1,4/2,4/3
    const dailyAvgSales = totalSales / daysElapsed;
    const dailyAvgBowls = totalBowls / daysElapsed;
    const remainingDays = 30 - daysElapsed;
    const estimatedSales = totalSales + dailyAvgSales * remainingDays;
    const estimatedBowls = totalBowls + dailyAvgBowls * remainingDays;
    console.log('\\n=== 着地見込 ===');
    console.log('日次平均売上: ¥' + Math.round(dailyAvgSales));
    console.log('日次平均碗数: ' + dailyAvgBowls.toFixed(1) + '碗');
    console.log('4月着地見込売上: ¥' + Math.round(estimatedSales));
    console.log('4月着地見込碗数: ' + Math.round(estimatedBowls) + '碗');
    console.log('目標540碗比: ' + Math.round(estimatedBowls / 540 * 100) + '%');
  });
});
req.on('error', e => console.error('Error:', e.message));
req.write(query);
req.end();
" 2>&1

node -e "
const https = require('https');

// GA4 API call using service account
const fs = require('fs');
const crypto = require('crypto');

const credPath = 'mcp-servers/ga4-mcp/credentials.json';
const creds = JSON.parse(fs.readFileSync(credPath, 'utf8'));

// Create JWT for Google OAuth2
function base64url(str) {
  return Buffer.from(str).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const now = Math.floor(Date.now() / 1000);
const payload = base64url(JSON.stringify({
  iss: creds.client_email,
  scope: 'https://www.googleapis.com/auth/analytics.readonly',
  aud: 'https://oauth2.googleapis.com/token',
  exp: now + 3600,
  iat: now
}));

const signInput = header + '.' + payload;
const sign = crypto.createSign('SHA256');
sign.update(signInput);
const sig = sign.sign(creds.private_key, 'base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
const jwt = signInput + '.' + sig;

// Exchange JWT for access token
const postData = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=' + jwt;
const tokenOptions = {
  hostname: 'oauth2.googleapis.com',
  path: '/token',
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    'Content-Length': Buffer.byteLength(postData)
  }
};

const tokenReq = https.request(tokenOptions, (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    const tokenData = JSON.parse(data);
    if (tokenData.error) {
      console.error('Token error:', JSON.stringify(tokenData));
      return;
    }
    const accessToken = tokenData.access_token;

    // Now call GA4 API - traffic sources for last 7 days
    const propertyId = '452176286';
    const reportBody = JSON.stringify({
      dateRanges: [{ startDate: '7daysAgo', endDate: 'yesterday' }],
      dimensions: [{ name: 'sessionSource' }, { name: 'sessionMedium' }],
      metrics: [
        { name: 'sessions' },
        { name: 'conversions' },
        { name: 'bounceRate' }
      ],
      orderBys: [{ metric: { metricName: 'sessions' }, desc: true }],
      limit: 15
    });

    const reportOptions = {
      hostname: 'analyticsdata.googleapis.com',
      path: '/v1beta/properties/' + propertyId + ':runReport',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + accessToken,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(reportBody)
      }
    };

    const reportReq = https.request(reportOptions, (reportRes) => {
      let reportData = '';
      reportRes.on('data', chunk => reportData += chunk);
      reportRes.on('end', () => {
        console.log('=== GA4 流入元分析 (直近7日) ===');
        const result = JSON.parse(reportData);
        if (result.error) {
          console.error('GA4 error:', JSON.stringify(result.error));
          return;
        }
        const rows = result.rows || [];
        rows.forEach(row => {
          const dims = row.dimensionValues.map(d => d.value).join('/');
          const metrics = row.metricValues.map(m => m.value);
          console.log(dims + ': sessions=' + metrics[0] + ' conv=' + metrics[1] + ' bounce=' + parseFloat(metrics[2]).toFixed(1) + '%');
        });
        console.log('TOKEN:', accessToken.substring(0, 20) + '...');
      });
    });
    reportReq.on('error', e => console.error('Report error:', e.message));
    reportReq.write(reportBody);
    reportReq.end();
  });
});
tokenReq.on('error', e => console.error('Token request error:', e.message));
tokenReq.write(postData);
tokenReq.end();
" 2>&1

