const https = require('https');
const fs = require('fs');
const crypto = require('crypto');

const credPath = 'mcp-servers/ga4-mcp/credentials.json';
const creds = JSON.parse(fs.readFileSync(credPath, 'utf8'));

function base64url(str) {
  return Buffer.from(str).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const now = Math.floor(Date.now() / 1000);
const payload = base64url(JSON.stringify({
  iss: creds.client_email,
  scope: 'https://www.googleapis.com/auth/analytics.readonly',
  aud: 'https://oauth2.googleapis.com/token',
  exp: now + 3600,
  iat: now
}));

const signInput = header + '.' + payload;
const sign = crypto.createSign('SHA256');
sign.update(signInput);
const sig = sign.sign(creds.private_key, 'base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
const jwt = signInput + '.' + sig;

const postData = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=' + jwt;
const tokenOptions = {
  hostname: 'oauth2.googleapis.com',
  path: '/token',
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(postData) }
};

const tokenReq = https.request(tokenOptions, (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    const tokenData = JSON.parse(data);
    if (tokenData.error) { console.error('Token error:', JSON.stringify(tokenData)); return; }
    const accessToken = tokenData.access_token;
    const propertyId = '452176286';

    // Funnel: cart-to-checkout-to-purchase step analysis
    const reportBody = JSON.stringify({
      dateRanges: [{ startDate: '7daysAgo', endDate: 'yesterday' }],
      dimensions: [{ name: 'eventName' }],
      metrics: [
        { name: 'eventCount' },
        { name: 'sessions' }
      ],
      dimensionFilter: {
        orGroup: {
          expressions: [
            { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'add_to_cart' } } },
            { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'begin_checkout' } } },
            { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'purchase' } } },
            { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'view_item' } } },
            { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'session_start' } } }
          ]
        }
      },
      orderBys: [{ metric: { metricName: 'eventCount' }, desc: true }]
    });

    const reportOptions = {
      hostname: 'analyticsdata.googleapis.com',
      path: '/v1beta/properties/' + propertyId + ':runReport',
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + accessToken, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(reportBody) }
    };

    const reportReq = https.request(reportOptions, (reportRes) => {
      let reportData = '';
      reportRes.on('data', chunk => reportData += chunk);
      reportRes.on('end', () => {
        console.log('=== GA4 ファネルイベント (直近7日) ===');
        const result = JSON.parse(reportData);
        if (result.error) { console.error('GA4 error:', JSON.stringify(result.error)); return; }
        const rows = result.rows || [];
        rows.forEach(row => {
          const event = row.dimensionValues[0].value;
          const [eventCount, sessions] = row.metricValues.map(m => m.value);
          console.log(event + ': count=' + eventCount + ' sessions=' + sessions);
        });

        // Calculate funnel rates
        const eventMap = {};
        rows.forEach(r => { eventMap[r.dimensionValues[0].value] = parseInt(r.metricValues[0].value); });
        const viewItem = eventMap['view_item'] || 0;
        const addToCart = eventMap['add_to_cart'] || 0;
        const beginCheckout = eventMap['begin_checkout'] || 0;
        const purchase = eventMap['purchase'] || 0;
        const sessionStart = eventMap['session_start'] || 0;

        console.log('\\n=== ファネル遷移率 ===');
        console.log('セッション数:', sessionStart);
        console.log('商品詳細 (view_item):', viewItem);
        console.log('カート追加 (add_to_cart):', addToCart, '→ 商品詳細比', viewItem ? (addToCart/viewItem*100).toFixed(1) + '%' : 'N/A');
        console.log('チェックアウト開始:', beginCheckout, '→ カート比', addToCart ? (beginCheckout/addToCart*100).toFixed(1) + '%' : 'N/A');
        console.log('購入完了 (purchase):', purchase, '→ チェックアウト比', beginCheckout ? (purchase/beginCheckout*100).toFixed(1) + '%' : 'N/A');
        console.log('全体CVR:', sessionStart ? (purchase/sessionStart*100).toFixed(2) + '%' : 'N/A');
      });
    });
    reportReq.on('error', e => console.error('Error:', e.message));
    reportReq.write(reportBody);
    reportReq.end();
  });
});
tokenReq.on('error', e => console.error('Error:', e.message));
tokenReq.write(postData);
tokenReq.end();
