// Analyze all PMAX data for top clickers and intent patterns
const https = require('https');
const fs = require('fs');
const crypto = require('crypto');

const credPath = 'credentials/google-service-account.json';
const creds = JSON.parse(fs.readFileSync(credPath, 'utf8'));

function base64url(str) {
  return Buffer.from(str).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const now = Math.floor(Date.now() / 1000);
const payload = base64url(JSON.stringify({
  iss: creds.client_email,
  scope: 'https://www.googleapis.com/auth/spreadsheets.readonly',
  aud: 'https://oauth2.googleapis.com/token',
  exp: now + 3600,
  iat: now
}));

const signInput = header + '.' + payload;
const sign = crypto.createSign('SHA256');
sign.update(signInput);
const sig = sign.sign(creds.private_key, 'base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
const jwt = signInput + '.' + sig;

const postData = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=' + jwt;
const tokenOptions = {
  hostname: 'oauth2.googleapis.com',
  path: '/token',
  method: 'POST',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(postData) }
};

const tokenReq = https.request(tokenOptions, (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    const tokenData = JSON.parse(data);
    if (tokenData.error) { console.error('Token error:', JSON.stringify(tokenData)); return; }
    const accessToken = tokenData.access_token;

    const spreadsheetId = '1Qw41z2YXJSbTRSj0ohIFBHw9SQdrFmIzi24KyTVSuxU';
    const range = encodeURIComponent('A1:L200');

    const sheetOptions = {
      hostname: 'sheets.googleapis.com',
      path: '/v4/spreadsheets/' + spreadsheetId + '/values/' + range,
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + accessToken }
    };

    const sheetReq = https.request(sheetOptions, (sheetRes) => {
      let sheetData = '';
      sheetRes.on('data', chunk => sheetData += chunk);
      sheetRes.on('end', () => {
        const result = JSON.parse(sheetData);
        if (result.error) { console.error('Sheets error:', JSON.stringify(result.error)); return; }
        const values = result.values || [];

        let totalClicks = 0, totalImpressions = 0, totalCost = 0, totalConversions = 0;
        let allRows = [];

        for (let i = 4; i < values.length; i++) {
          const row = values[i];
          if (!row || row.length < 4) continue;
          const keyword = row[0];
          const clicks = parseInt(row[3]) || 0;
          const impressions = parseInt(row[4]) || 0;
          const ctr = row[5];
          const cost = parseFloat(row[8]) || 0;
          const cvr = row[9];
          const conversions = parseFloat(row[10]) || 0;
          const cpa = parseFloat(row[11]) || 0;

          totalClicks += clicks;
          totalImpressions += impressions;
          totalCost += cost;
          totalConversions += conversions;

          allRows.push({ keyword, clicks, impressions, ctr, cost, cvr, conversions, cpa });
        }

        // Sort by impressions for top reach terms
        const byImpressions = [...allRows].sort((a, b) => b.impressions - a.impressions);
        const byClicks = [...allRows].sort((a, b) => b.clicks - a.clicks);

        // Categorize keywords
        const giftKeywords = allRows.filter(r => r.keyword.match(/プレゼント|ギフト|贈り物|祝い/));
        const sakiKeywords = allRows.filter(r => r.keyword.match(/酒器|ぐい呑|おちょこ|とっくり|徳利/));
        const glassKeywords = allRows.filter(r => r.keyword.match(/グラス|ガラス/));
        const badKeywords = allRows.filter(r => r.impressions > 10 && r.clicks === 0);

        console.log('\\n=== PMAX総計（2月1日〜28日） ===');
        console.log('総表示回数:', totalImpressions);
        console.log('総クリック数:', totalClicks);
        console.log('CTR:', totalImpressions ? (totalClicks/totalImpressions*100).toFixed(2) + '%' : 'N/A');
        console.log('総費用: ¥' + Math.round(totalCost));
        console.log('総コンバージョン:', totalConversions);

        console.log('\\n=== 表示回数TOP10 ===');
        byImpressions.slice(0, 10).forEach(r => {
          console.log(r.keyword + ': imp=' + r.impressions + ' clicks=' + r.clicks + ' CVR=' + r.cvr + ' conv=' + r.conversions);
        });

        console.log('\\n=== ギフト系語句（' + giftKeywords.length + '件） ===');
        giftKeywords.slice(0, 8).forEach(r => console.log(r.keyword + ': imp=' + r.impressions + ' clicks=' + r.clicks));

        console.log('\\n=== 表示多・クリックゼロ除外候補 ===');
        badKeywords.sort((a, b) => b.impressions - a.impressions).slice(0, 10).forEach(r => {
          console.log('❌ ' + r.keyword + ': imp=' + r.impressions + ' clicks=0');
        });
      });
    });
    sheetReq.on('error', e => console.error('Error:', e.message));
    sheetReq.end();
  });
});
tokenReq.on('error', e => console.error('Error:', e.message));
tokenReq.write(postData);
tokenReq.end();
